args.sparql:
SELECT ?player WHERE {
  ?player wdt:P54 wd:Q7875 .
  ?player wdt:P580 ?start .
  ?player wdt:P585 ?end .
  FILTER (math:year(?start) <= 1997 && math:year(?end) >= 1997 && math:year(?end) = 1998)
}

SELECT ?player WHERE {
  ?player wdt:P54 wd:Q7875 .
  ?player wdt:P580 ?start_date .
  ?player wdt:P585 ?end_date .
  FILTER (REGEX(STR(?start_date), "1997") && REGEX(STR(?end_date), "1998"))
}

SELECT ?player WHERE {
  ?player wdt:P1277 wd:Q7875 .
  ?player wdt:P4588 1997 .
  ?player wdt:P585 ?end .
  FILTER (SUBSTR(STR(?end), 1, 4) = "1998")
}
